import React, { useState, useRef } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing } from '../types';
import { checkListingContent } from '../services/geminiService';
import { Camera, Video, MapPin, Loader2, CheckCircle, ShieldCheck, Compass, MapPinned, Wallet, Award, Sparkles } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [currencyType, setCurrencyType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [selectedCoin, setSelectedCoin] = useState('');
  const [payoutAddress, setPayoutAddress] = useState('');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [location, setLocation] = useState(user.location || { address: '', lat: 0, lng: 0 });

  const cryptoCoins = ['Solana', 'Ethereum', 'Monad', 'Base', 'Sui', 'Polygon', 'Bitcoin'];

  const handleAutoLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        const { latitude, longitude } = position.coords;
        try {
          const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&addressdetails=1&accept-language=${lang}`);
          const data = await response.json();
          const { address } = data;
          const country = address.country || '';
          const city = address.city || address.town || address.village || address.state || '';
          const neighborhood = address.suburb || address.neighbourhood || address.residential || address.road || '';
          const fullAddress = [country, city, neighborhood].filter(Boolean).join(', ');
          setLocation({ address: fullAddress, lat: latitude, lng: longitude });
        } catch (e) {
          setLocation({ address: `${latitude.toFixed(2)}, ${longitude.toFixed(2)}`, lat: latitude, lng: longitude });
        } finally {
          setIsLocating(false);
        }
      }, () => {
        alert(lang === 'ar' ? 'فشل تحديد الموقع' : 'Location failed');
        setIsLocating(false);
      });
    }
  };

  /**
   * SYSTEM_PUBLISH_COMMAND implementation
   */
  const handlePublish = async () => {
    // 1️⃣ Check completeness
    if (!title || !description || !price || images.length < 1) {
      alert(lang === 'ar' ? 'بيانات غير مكتملة' : 'INCOMPLETE_DATA');
      return;
    }

    // 2️⃣ Verify Owner (assuming user.isVerified or signed up)
    // For demo purposes, we check if user object exists. In production, check a 'verified' flag.
    const isOwnerVerified = user.isVerified !== false; // Default true if not explicitly false
    if (!isOwnerVerified) {
      alert(lang === 'ar' ? 'الحساب غير موثق' : 'OWNER_NOT_VERIFIED');
      return;
    }

    setLoading(true);

    // 3️⃣ AI Moderation Check (Status -> AI_REVIEW)
    try {
      const moderationResult = await checkListingContent(title, description);

      if (moderationResult.status !== 'APPROVED') {
        alert(lang === 'ar' ? 'تم رفض الإعلان من قبل الذكاء الاصطناعي' : 'AI_REJECTED');
        setLoading(false);
        return;
      }

      // 4️⃣ Final Publishing (Status -> PUBLISHED, Visibility -> PUBLIC)
      const now = new Date().toISOString();
      const finalListing: Listing = {
        id: 'l_' + Date.now(), 
        ownerId: user.id, 
        ownerName: user.fullName, 
        ownerUsername: user.username,
        ownerAvatar: user.avatar, 
        title, 
        description, 
        type: ListingType.RENT, 
        price: parseFloat(price),
        currency: 'USD', 
        currencyType, 
        payoutAddress: currencyType === CurrencyType.CRYPTO ? `${selectedCoin}: ${payoutAddress}` : payoutAddress, 
        category, 
        location,
        images, 
        video: video || undefined, 
        rentalPeriod: period, 
        createdAt: now,
        views: 0, 
        likes: 0, 
        rating: 0, 
        isAiApproved: true,

        // Publishing Fields
        status: 'PUBLISHED',
        visibility: 'PUBLIC',
        review_state: 'APPROVED',
        published_at: now,
        updated_at: now,
        is_deleted: false
      };

      onCreated(finalListing);

      // Navigate to success state
      setTimeout(() => setStep(5), 1500);
    } catch (error) {
      alert(lang === 'ar' ? 'خطأ في عملية النشر' : 'PUBLISHING_ERROR');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-10 bg-white dark:bg-gray-900 rounded-[4.5rem] my-10 border dark:border-gray-800 shadow-[0_50px_100px_-20px_rgba(0,0,0,0.1)]">
      <div className="flex gap-3 mb-16">
        {[1,2,3,4,5].map(s => (
          <div key={s} className="flex-1">
            <div className={`h-2.5 rounded-full transition-all duration-700 ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />
          </div>
        ))}
      </div>

      {step === 1 && (
        <div className="space-y-10 animate-in slide-in-from-right duration-500">
          <div className="text-center">
            <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{lang === 'ar' ? 'المعرض المرئي' : 'Media Showcase'}</h2>
            <p className="text-[11px] text-gray-400 font-bold uppercase tracking-widest mt-4">Upload photos and video content</p>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-5 gap-4">
            {images.map((img, i) => (
              <div key={i} className="group relative aspect-square overflow-hidden rounded-[2.2rem] border-2 border-brand/5">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(images.filter((_, idx) => idx !== i))} className="absolute top-2 right-2 p-1.5 bg-brand text-white rounded-full"><Award size={10} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <button onClick={() => imageInputRef.current?.click()} className="aspect-square bg-gray-50 dark:bg-gray-800 rounded-[2.2rem] border-4 border-dashed flex flex-col items-center justify-center text-gray-300 hover:text-brand transition-all">
                <Camera size={36} />
                <input type="file" ref={imageInputRef} multiple accept="image/*" className="hidden" onChange={e => {
                  const target = e.target as HTMLInputElement;
                  if (target.files) {
                    const newImages = Array.from(target.files).map(f => URL.createObjectURL(f));
                    setImages([...images, ...newImages].slice(0, 5));
                  }
                }} />
              </button>
            )}
          </div>

          <button onClick={() => videoInputRef.current?.click()} className={`w-full p-8 rounded-[2.5rem] border-2 border-dashed transition-all flex items-center justify-center gap-4 ${video ? 'bg-brand/5 border-brand text-brand' : 'bg-gray-50 dark:bg-gray-800 text-gray-400'}`}>
            <Video size={24} />
            <span className="font-black uppercase text-xs">{video ? (lang === 'ar' ? 'تم اختيار الفيديو' : 'Video Selected') : (lang === 'ar' ? 'إضافة فيديو (اختياري)' : 'Add Identity Video')}</span>
            <input type="file" ref={videoInputRef} accept="video/*" className="hidden" onChange={e => {
              const target = e.target as HTMLInputElement;
              if (target.files?.[0]) setVideo(URL.createObjectURL(target.files[0]));
            }} />
          </button>

          <button disabled={images.length < 1} onClick={() => setStep(2)} className="w-full py-7 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-xl transition-all disabled:opacity-30">
            {t.next}
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-10 animate-in slide-in-from-right duration-500">
          <div className="text-center">
            <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{lang === 'ar' ? 'هوية المنتج' : 'Item Signature'}</h2>
          </div>

          <div className="space-y-4">
            <input type="text" placeholder={lang === 'ar' ? 'عنوان الإعلان*' : 'Listing Title*'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-6 rounded-[2.2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-black text-lg focus:ring-2 focus:ring-brand" />
            <textarea placeholder={lang === 'ar' ? 'وصف تفصيلي*' : 'Description*'} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-6 rounded-[2.2rem] bg-gray-50 dark:bg-gray-800 dark:text-white h-40 outline-none font-bold focus:ring-2 focus:ring-brand" />

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-6 rounded-[2.2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-black uppercase text-xs">
                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <button onClick={handleAutoLocation} className="w-full p-6 bg-brand text-white rounded-[2.2rem] flex items-center justify-center gap-2 font-black uppercase text-xs shadow-lg">
                {isLocating ? <Loader2 className="animate-spin" size={18} /> : <Compass size={18} />} {lang === 'ar' ? 'تحديد الموقع' : 'Fetch Address'}
              </button>
            </div>

            <div className="p-6 bg-brand/5 rounded-[2.5rem] border flex items-center gap-4">
               <MapPinned size={28} className="text-brand" />
               <input type="text" value={location.address} readOnly className="flex-1 bg-transparent font-black dark:text-white text-xs outline-none" placeholder={lang === 'ar' ? 'العنوان سيظهر هنا...' : 'Address will appear here...'} />
            </div>
          </div>

          <div className="flex gap-4">
             <button onClick={() => setStep(1)} className="flex-1 py-6 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-[2rem] font-black uppercase">{t.back}</button>
             <button disabled={!title || !description || !location.address} onClick={() => setStep(3)} className="flex-[2] py-6 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl">{t.next}</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-10">
          <div className="text-center">
            <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter italic">{t.payoutMethod}</h2>
          </div>

          <div className="flex p-2 bg-gray-100 dark:bg-gray-800 rounded-[3rem] gap-2">
            <button onClick={() => setCurrencyType(CurrencyType.CRYPTO)} className={`flex-1 py-5 rounded-[2.5rem] font-black uppercase text-[10px] transition-all ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow-lg' : 'text-gray-400'}`}>{t.crypto}</button>
            <button onClick={() => setCurrencyType(CurrencyType.LOCAL)} className={`flex-1 py-5 rounded-[2.5rem] font-black uppercase text-[10px] transition-all ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow-lg' : 'text-gray-400'}`}>{t.local}</button>
          </div>

          <div className="space-y-6">
            {currencyType === CurrencyType.CRYPTO ? (
              <div className="grid grid-cols-2 gap-2">
                {cryptoCoins.map(coin => (
                  <button key={coin} onClick={() => setSelectedCoin(coin)} className={`p-4 rounded-2xl border-2 text-[10px] font-black uppercase transition-all ${selectedCoin === coin ? 'border-brand bg-brand/5 text-brand' : 'border-transparent bg-gray-50 dark:bg-gray-800 dark:text-white'}`}>{coin}</button>
                ))}
              </div>
            ) : null}
            <input type="text" placeholder={lang === 'ar' ? 'عنوان المحفظة أو البريد*' : 'Wallet or Email*'} value={payoutAddress} onChange={e => setPayoutAddress(e.target.value)} className="w-full p-6 rounded-[2rem] bg-gray-50 dark:bg-gray-800 dark:text-white font-bold outline-none focus:ring-2 focus:ring-brand" />
          </div>

          <div className="flex gap-4">
             <button onClick={() => setStep(2)} className="flex-1 py-6 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-[2rem] font-black uppercase">{t.back}</button>
             <button disabled={!payoutAddress} onClick={() => setStep(4)} className="flex-[2] py-6 bg-brand text-white rounded-[2rem] font-black uppercase shadow-xl">{t.next}</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-12">
          <div className="text-center">
            <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'المراجعة والنشر' : 'Review & Seal'}</h2>
          </div>

          <div className="bg-gray-50 dark:bg-gray-800 rounded-[3rem] p-10 flex flex-col items-center">
            <ShieldCheck size={64} className="text-brand mb-6" />
            <div className="flex items-center gap-2 mb-8">
               <span className="text-5xl font-black text-brand tracking-tighter">${price || '0'}</span>
               <span className="text-xs font-bold text-gray-400 uppercase">USD / {t.periods[period]}</span>
            </div>
            <input type="number" placeholder="Price" value={price} onChange={e => setPrice(e.target.value)} className="w-32 bg-transparent border-b-2 border-brand text-center text-2xl font-black dark:text-white outline-none mb-10" />

            <div className="w-full border-t dark:border-gray-700 pt-8 grid grid-cols-2 gap-4">
               <div className="text-center">
                  <p className="text-[9px] font-black text-gray-400 uppercase">Status</p>
                  <p className="text-xs font-black text-green-500 uppercase">Valid</p>
               </div>
               <div className="text-center">
                  <p className="text-[9px] font-black text-gray-400 uppercase">AI Shield</p>
                  <p className="text-xs font-black text-blue-500 uppercase">Ready</p>
               </div>
            </div>
          </div>

          <button onClick={handlePublish} disabled={loading || !price} className="w-full py-8 bg-brand text-white rounded-[2.5rem] font-black text-xl uppercase tracking-widest shadow-2xl flex items-center justify-center gap-4 active:scale-95 transition-all">
             {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} {t.securePublish}
          </button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-20 space-y-8">
          <div className="w-32 h-32 bg-green-500 text-white rounded-[3rem] flex items-center justify-center mx-auto shadow-xl animate-bounce">
            <CheckCircle size={64} />
          </div>
          <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter">{t.aiApproved}</h2>
          <button onClick={() => navigate('/')} className="w-full py-7 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-xl transition-all">
            Return to Market
          </button>
        </div>
      )}
    </div>
  );
};

