const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [estimating, setEstimating] = useState(false);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const [images, setImages] = useState<string[]>([]);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [location, setLocation] = useState(user.location || { address: '', lat: 0, lng: 0 });

  const handleEstimate = async () => {
    if (!title || !description) return;
    setEstimating(true);
    const est = await estimateRentalPrice(title, description, user.currencyPreference || 'USD');
    setPrice(est.toString());
    setEstimating(false);
  };

  const handlePublish = async () => {
    setLoading(true);
    const moderation = await checkListingContent(title, description);
    if (moderation.status === 'REJECTED') {
      alert(moderation.reason);
      setLoading(false);
      return;
    }

    const now = new Date().toISOString();
    const finalListing: Listing = {
      id: 'l_' + Date.now(),
      ownerId: user.id,
      ownerName: user.fullName,
      ownerUsername: user.username,
      ownerAvatar: user.avatar,
      title,
      description,
      type: ListingType.RENT,
      price: parseFloat(price),
      currency: user.currencyPreference || 'USD',
      currencyType: CurrencyType.LOCAL,
      payoutAddress: 'Local Wallet',
      category,
      location,
      images,
      rentalPeriod: period,
      createdAt: now,
      views: 0,
      likes: 0,
      rating: 0,
      isAiApproved: true,
      unavailableDates: [],
      status: 'PUBLISHED',
      visibility: 'PUBLIC',
      review_state: 'APPROVED',
      published_at: now,
      updated_at: now,
      is_deleted: false
    };

    onCreated(finalListing);
    setStep(5);
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto p-10 bg-white dark:bg-gray-900 rounded-[4.5rem] my-10 border dark:border-gray-800 shadow-2xl">
      <div className="flex gap-2 mb-12">
        {[1,2,3,4].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-gray-100'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
            <h2 className="text-3xl font-black dark:text-white uppercase italic">Step 1: Visuals</h2>
            <p className="text-xs text-gray-400 mt-2">Upload high-quality Base64 photos</p>
          </div>
          <div className="grid grid-cols-3 gap-4">
            {images.map((img, i) => (
              <img key={i} src={img} className="aspect-square rounded-[2rem] object-cover border-2 border-brand/10" />
            ))}
            <button onClick={() => imageInputRef.current?.click()} className="aspect-square bg-gray-50 dark:bg-gray-800 rounded-[2rem] border-4 border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400 hover:text-brand transition-all">
              <Camera size={32} />
              <input type="file" ref={imageInputRef} multiple className="hidden" onChange={e => {
                const files = Array.from(e.target.files || []);
                files.forEach(f => {
                  const r = new FileReader();
                  r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
                  r.readAsDataURL(f);
                });
              }} />
            </button>
          </div>
          <button onClick={() => setStep(2)} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-xl">Next Step</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right">
          <h2 className="text-3xl font-black dark:text-white uppercase italic text-center">Step 2: Details</h2>
          <input type="text" placeholder="Item Title" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-6 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-[2rem] outline-none font-bold" />
          <textarea placeholder="Description" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-6 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-[2rem] outline-none h-32 font-medium" />
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="flex-1 py-5 bg-gray-100 rounded-[2rem] font-bold text-gray-400">Back</button>
            <button onClick={() => setStep(3)} className="flex-[2] py-5 bg-brand text-white rounded-[2rem] font-black uppercase">Continue</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-3xl font-black dark:text-white uppercase italic text-center">Step 3: Pricing</h2>
          <div className="bg-gray-50 dark:bg-gray-800 p-8 rounded-[3rem] text-center border dark:border-gray-700">
             <div className="flex items-center justify-center gap-2 mb-6">
                <input type="number" value={price} onChange={e => setPrice(e.target.value)} className="w-32 bg-transparent border-b-2 border-brand text-center text-3xl font-black dark:text-white outline-none" placeholder="0.00" />
                <span className="font-black text-brand">{user.currencyPreference || 'USD'}</span>
             </div>
             <button onClick={handleEstimate} disabled={estimating} className="px-8 py-3 bg-brand/10 text-brand rounded-full font-black text-[10px] uppercase flex items-center gap-2 mx-auto hover:bg-brand hover:text-white transition-all">
                {estimating ? <Loader2 className="animate-spin" size={14} /> : <Zap size={14} />} 
                {lang === 'ar' ? 'تخمين السعر الذكي' : 'AI Price Estimate'}
             </button>
          </div>
          <div className="grid grid-cols-2 gap-4">
             {Object.values(RentalPeriod).map(p => (
               <button key={p} onClick={() => setPeriod(p)} className={`py-4 rounded-2xl font-black text-[10px] uppercase transition-all ${period === p ? 'bg-brand text-white shadow-lg' : 'bg-gray-50 dark:bg-gray-800 text-gray-400'}`}>Per {p}</button>
             ))}
          </div>
          <button onClick={() => setStep(4)} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-xl">Review Listing</button>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <ShieldCheck size={64} className="mx-auto text-brand" />
          <h2 className="text-3xl font-black dark:text-white uppercase italic">Ready to Go</h2>
          <p className="text-sm text-gray-500">Your item will be published to the global market instantly.</p>
          <button onClick={handlePublish} disabled={loading} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-xl flex items-center justify-center gap-4">
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} Secure Publish
          </button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center space-y-6 py-10 animate-in fade-in">
          <div className="w-24 h-24 bg-green-500 text-white rounded-full flex items-center justify-center mx-auto shadow-2xl">
            <CheckCircle size={48} />
          </div>
          <h2 className="text-4xl font-black dark:text-white uppercase italic">Item Live!</h2>
          <button onClick={() => navigate('/')} className="px-10 py-4 bg-brand text-white rounded-full font-black uppercase">Marketplace</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useParams } from 'react-router-dom';
import { User, Gender, Listing } from './types';
import Navbar from './components/Navbar';
import ListingCard from './components/ListingCard';
import HomePage from './pages/HomePage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import SubscriptionPage from './pages/SubscriptionPage';
import { translations } from './i18n';
import { POINTS_SYSTEM, CURRENCIES } from './constants';
import { Camera, MapPinned, Compass, Box, Star, ChevronRight, Coins, Sparkles, Loader2, MapPin, ShieldCheck, Award } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
  const [isDarkMode, setIsDarkMode] = useState(false);

  const [user, setUser] = useState<User | null>(() => {
    try {
      const saved = localStorage.getItem('my_rents_user');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  });

  const [allListings, setAllListings] = useState<Listing[]>(() => {
    try {
      const saved = localStorage.getItem('my_rents_listings');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    if (user) localStorage.setItem('my_rents_user', JSON.stringify(user));
    else localStorage.removeItem('my_rents_user');
  }, [user]);

  useEffect(() => {
    localStorage.setItem('my_rents_listings', JSON.stringify(allListings));
  }, [allListings]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];

  const addPoints = (amount: number) => {
    setUser(prev => prev ? { ...prev, points: prev.points + amount } : null);
  };

  const handleCurrencyChange = (code: string) => {
    setUser(prev => prev ? { ...prev, currencyPreference: code } : null);
  };

  const handleSignUpFinish = (e: React.FormEvent, data: any) => {
    e.preventDefault();
    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: data.fullName,
      username: data.username,
      email: data.email,
      avatar: data.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: data.location,
      status: 'Member',
      points: 100,
      listingsCount: 0,
      walletBalance: 0,
      currencyPreference: 'USD',
      trustScore: 75,
      badges: ['NEW_MEMBER'],
      payoutMethods: {},
      blockedUsers: [],
      isVerified: true
    };
    setUser(newUser);
  };

  const ProfileView = () => {
    const { username } = useParams<{ username?: string }>();
    const isSelf = !username || (user && username === user.username);
    const displayUser = isSelf ? user : null; 
    const userSpecificListings = allListings.filter(l => l.ownerUsername === (username || user?.username));

    return (
      <div className="p-8 text-center max-w-4xl mx-auto animate-in fade-in">
        <div className="bg-white dark:bg-gray-900 rounded-[3.5rem] p-10 shadow-sm border dark:border-gray-800">
          <div className="relative inline-block mb-6">
            <img src={displayUser?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${username || user?.username}`} className="w-32 h-32 rounded-full border-4 border-brand object-cover shadow-2xl bg-gray-100" />
            <div className="absolute -bottom-2 -right-2 bg-brand text-white p-2 rounded-xl shadow-lg">
              <ShieldCheck size={18} fill="currentColor" />
            </div>
          </div>

          <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter mb-1 italic">{displayUser?.fullName || username || user?.fullName}</h1>
          <p className="text-[#CCCCCC] mb-4 font-bold">@{username || user?.username}</p>

          <div className="flex justify-center gap-2 mb-8">
             {displayUser?.badges.map(b => (
               <span key={b} className="px-3 py-1 bg-brand/5 text-brand rounded-full text-[8px] font-black uppercase tracking-widest border border-brand/10 flex items-center gap-1">
                 <Award size={10} /> {b.replace('_', ' ')}
               </span>
             ))}
          </div>

          <div className="grid grid-cols-2 gap-4 mb-10">
             <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest block mb-1">Trust Score</span>
                <span className="text-3xl font-black text-brand">{isSelf ? user?.trustScore : '88'}%</span>
             </div>
             <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest block mb-1">Points</span>
                <span className="text-3xl font-black text-brand">{isSelf ? user?.points : '1.2k'}</span>
             </div>
          </div>

          <div className="mb-10 text-left">
            <h2 className="text-lg font-black dark:text-white uppercase tracking-tighter mb-4 px-2">Active Listings</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {userSpecificListings.map(l => (
                <ListingCard key={l.id} listing={l} lang={lang} isOwner={l.ownerId === user?.id} onDelete={(id) => setAllListings(prev => prev.filter(item => item.id !== id))} onAddPoints={addPoints} />
              ))}
            </div>
          </div>

          {isSelf && (
            <button onClick={() => { setUser(null); localStorage.clear(); }} className="w-full mt-6 py-4 text-red-500 font-black uppercase tracking-widest text-[10px] hover:underline transition-all">
              {t.logout}
            </button>
          )}
        </div>
      </div>
    );
  };

  const SignUpPage = () => {
    const [signupData, setSignupData] = useState({
      avatar: '', fullName: '', username: '', location: { address: '', lat: 0, lng: 0 },
      email: '', password: '', agreed: false
    });

    return (
      <div className="w-full max-w-2xl px-6 py-12 mx-auto animate-in fade-in">
        <div className="text-center mb-10">
