import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const checkListingContent = async (title: string, description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Review this rental listing for safety and community guidelines. Is it safe to publish? Reply with ONLY 'APPROVED' or 'REJECTED' followed by a short reason.
      Title: ${title}
      Description: ${description}`,
      config: {
        systemInstruction: "You are AI my rents. You must ensure all items are for RENT only. No illegal items. No sales.",
      }
    });
    return response.text?.includes('APPROVED') ? { status: 'APPROVED' } : { status: 'REJECTED', reason: response.text };
  } catch (error) {
    return { status: 'APPROVED' };
  }
};

export const estimateRentalPrice = async (title: string, description: string, currency: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Estimate a fair DAILY rental price for this item in ${currency}. Reply with ONLY the numeric value.
      Item: ${title}
      Details: ${description}`,
    });
    const priceStr = response.text?.replace(/[^0-9.]/g, '') || "10";
    return parseFloat(priceStr);
  } catch (error) {
    return 10;
  }
};

// Added getAISupportResponse for AI customer support interaction
export const getAISupportResponse = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: query,
      config: {
        systemInstruction: "You are the helpful AI support agent for 'my rents', a peer-to-peer rental marketplace. Assist users with questions about listing items, renting, and earning points.",
      },
    });
    return response.text || "I'm sorry, I couldn't generate a response.";
  } catch (error) {
    console.error("AI Support Error:", error);
    return "Support is currently unavailable. Please try again later.";
  }
};

export const getDiscoveryInsights = async (location: string, query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Find me good places or types of items available for rent near ${location} for ${query}.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: { latLng: { latitude: 24.7136, longitude: 46.6753 } } // Riyadh as default if no location
        }
      }
    });
    return {
      text: response.text,
      links: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    return { text: "Search failed. Please try again.", links: [] };
  }
};

import React, { useState, useRef } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing } from '../types';
import { checkListingContent, estimateRentalPrice } from '../services/geminiService';
import { Camera, Compass, MapPinned, Award, Sparkles, Loader2, CheckCircle, ShieldCheck, Zap, Calendar } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [estimating, setEstimating] = useState(false);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const [images, setImages] = useState<string[]>([]);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [location, setLocation] = useState(user.location || { address: '', lat: 0, lng: 0 });

  const handleEstimate = async () => {
    if (!title || !description) return;
    setEstimating(true);
    const est = await estimateRentalPrice(title, description, user.currencyPreference || 'USD');
    setPrice(est.toString());
    setEstimating(false);
  };

  const handlePublish = async () => {
    setLoading(true);
    const moderation = await checkListingContent(title, description);
    if (moderation.status === 'REJECTED') {
      alert(moderation.reason);
      setLoading(false);
      return;
    }

    const now = new Date().toISOString();
    const finalListing: Listing = {
      id: 'l_' + Date.now(),
      ownerId: user.id,
      ownerName: user.fullName,
      ownerUsername: user.username,
      ownerAvatar: user.avatar,
      title,
      description,
      type: ListingType.RENT,
      price: parseFloat(price),
      currency: user.currencyPreference || 'USD',
      currencyType: CurrencyType.LOCAL,
      payoutAddress: 'Local Wallet',
      category,
      location,
      images,
      rentalPeriod: period,
      createdAt: now,
      views: 0,
      likes: 0,
      rating: 0,
      isAiApproved: true,
      unavailableDates: [],
      status: 'PUBLISHED',
      visibility: 'PUBLIC',
      review_state: 'APPROVED',
      published_at: now,
      updated_at: now,
      is_deleted: false
    };

    onCreated(finalListing);
    setStep(5);
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto p-10 bg-white dark:bg-gray-900 rounded-[4.5rem] my-10 border dark:border-gray-800 shadow-2xl">
      <div className="flex gap-2 mb-12">
        {[1,2,3,4].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-gray-100'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <div className="text-center">
            <h2 className="text-3xl font-black dark:text-white uppercase italic">Step 1: Visuals</h2>
            <p className="text-xs text-gray-400 mt-2">Upload high-quality Base64 photos</p>
          </div>
          <div className="grid grid-cols-3 gap-4">
            {images.map((img, i) => (
              <img key={i} src={img} className="aspect-square rounded-[2rem] object-cover border-2 border-brand/10" />
            ))}
            <button onClick={() => imageInputRef.current?.click()} className="aspect-square bg-gray-50 dark:bg-gray-800 rounded-[2rem] border-4 border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400 hover:text-brand transition-all">
              <Camera size={32} />
              <input type="file" ref={imageInputRef} multiple className="hidden" onChange={e => {
                const files = Array.from(e.target.files || []);
                // Fixed type error: explicitly casting the file item to File
                files.forEach((f: File) => {
                  const r = new FileReader();
                  r.onload = (ev) => setImages(prev => [...prev, ev.target?.result as string]);
                  r.readAsDataURL(f);
                });
              }} />
            </button>
          </div>
          <button onClick={() => setStep(2)} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-xl">Next Step</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right">
          <h2 className="text-3xl font-black dark:text-white uppercase italic text-center">Step 2: Details</h2>
          <input type="text" placeholder="Item Title" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-6 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-[2rem] outline-none font-bold" />
          <textarea placeholder="Description" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-6 bg-gray-50 dark:bg-gray-800 dark:text-white rounded-[2rem] outline-none h-32 font-medium" />
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="flex-1 py-5 bg-gray-100 rounded-[2rem] font-bold text-gray-400">Back</button>
            <button onClick={() => setStep(3)} className="flex-[2] py-5 bg-brand text-white rounded-[2rem] font-black uppercase">Continue</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right">
          <h2 className="text-3xl font-black dark:text-white uppercase italic text-center">Step 3: Pricing</h2>
          <div className="bg-gray-50 dark:bg-gray-800 p-8 rounded-[3rem] text-center border dark:border-gray-700">
             <div className="flex items-center justify-center gap-2 mb-6">
                <input type="number" value={price} onChange={e => setPrice(e.target.value)} className="w-32 bg-transparent border-b-2 border-brand text-center text-3xl font-black dark:text-white outline-none" placeholder="0.00" />
                <span className="font-black text-brand">{user.currencyPreference || 'USD'}</span>
             </div>
             <button onClick={handleEstimate} disabled={estimating} className="px-8 py-3 bg-brand/10 text-brand rounded-full font-black text-[10px] uppercase flex items-center gap-2 mx-auto hover:bg-brand hover:text-white transition-all">
                {estimating ? <Loader2 className="animate-spin" size={14} /> : <Zap size={14} />} 
                {lang === 'ar' ? 'تخمين السعر الذكي' : 'AI Price Estimate'}
             </button>
          </div>
          <div className="grid grid-cols-2 gap-4">
             {Object.values(RentalPeriod).map(p => (
               <button key={p} onClick={() => setPeriod(p)} className={`py-4 rounded-2xl font-black text-[10px] uppercase transition-all ${period === p ? 'bg-brand text-white shadow-lg' : 'bg-gray-50 dark:bg-gray-800 text-gray-400'}`}>Per {p}</button>
             ))}
          </div>
          <button onClick={() => setStep(4)} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-xl">Review Listing</button>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 text-center animate-in zoom-in-95">
          <ShieldCheck size={64} className="mx-auto text-brand" />
          <h2 className="text-3xl font-black dark:text-white uppercase italic">Ready to Go</h2>
          <p className="text-sm text-gray-500">Your item will be published to the global market instantly.</p>
          <button onClick={handlePublish} disabled={loading} className="w-full py-6 bg-brand text-white rounded-[2.5rem] font-black uppercase shadow-xl flex items-center justify-center gap-4">
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} Secure Publish
          </button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center space-y-6 py-10 animate-in fade-in">
          <div className="w-24 h-24 bg-green-500 text-white rounded-full flex items-center justify-center mx-auto shadow-2xl">
            <CheckCircle size={48} />
          </div>
          <h2 className="text-4xl font-black dark:text-white uppercase italic">Item Live!</h2>
          <button onClick={() => navigate('/')} className="px-10 py-4 bg-brand text-white rounded-full font-black uppercase">Marketplace</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;
